INSERT INTO `categories` VALUES (1,"burgers","Burgers","Selezione di burger con polpette di carne, verdure fresche e salse.",""),(2,"bites","Bites","Bocconcini e nuggets di carne, ideali come spuntino o da condividere.",""),(3,"wraps","Wraps","Piadine farcite con ingredienti freschi, carne e salse a scelta.",""),(4,"sides","Sides","Contorni per accompagnare il pasto: patatine, anelli di cipolla e altro.",""),(5,"sauces","Sauces","Salse artigianali disponibili in vari gusti, dalla delicata alla piccante.",""),(6,"drinks","Drinks","Bevande fredde e calde: bibite, succhi, milkshake e molto altro.",""),(7,"desserts","Desserts","Dolci e sfizi zuccherati per concludere il pasto.",""),(8,"menus","Menus","Combinazioni complete con burger, contorno e bevanda a prezzo fisso.","");
