LOCK TABLES `reviews` WRITE;
/*!40000 ALTER TABLE `reviews` DISABLE KEYS */;
INSERT INTO `reviews` VALUES (1,1,"un-esperienza-preistorica-indimenticabile","Un\'esperienza preistorica indimenticabile","Il T-Rex Prime Burger è semplicemente straordinario. La carne ha un sapore profondo e autentico che ricorda veramente i dinosauri preistorici. Ogni morso è un viaggio nel tempo.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(2,2,"veloce-come-un-raptor","Veloce come un Raptor","Il Raptor Double Smash non mi ha deluso. La texture a doppio strato e il gusto intenso affumicato lo rendono un must. Incredibilmente soddisfacente.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(3,3,"croccantezza-perfetta","Croccantezza perfetta","Lo Stego Crunch Burger vive al suo nome. La croccantezza del bordo combinata con la succosità del centro è un\'armonia di contrasti. Davvero bello!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(4,4,"monumentale-come-un-bronto","Monumentale come un Bronto","Il Bronto Tower Burger è mastodontico nel migliore dei modi. Una carne sanguigna e intensa che mantiene il carattere primordiale fino all\'ultimo morso.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(5,5,"un-classico-reinventato","Un classico reinventato","Il Cretaceous Classic Burger rappresenta eleganza e robustezza. Il profilo gustativo è sofisticato pur mantenendo l\'autenticità di un burger giurassico.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(6,6,"snack-addictive-e-croccanti","Snack addictive e croccanti","Le Raptor Crispy Bites sono perfette per uno snack veloce. Croccanti, sapide e leggermente speziate. Non riesco a smettere di mangiarle!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(7,7,"nostalgici-e-deliziosi","Nostalgici e deliziosi","I Triassic Chicken Nuggets ricordano i classici della mia infanzia ma con un twist paleontologico. Morbidi dentro, croccanti fuori, semplicemente perfetti.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(8,8,"mini-bocconi-di-piacere","Mini bocconi di piacere","I Compsognathus Mini Bites hanno un sapore delicato e armonico. Perfetti per chi vuole assaggiare senza appesantirsi. Una scelta intelligente.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(9,9,"un-esplosione-di-sapori","Un\'esplosione di sapori","Le Meteor Pop Bites sono sorprendenti e affascinanti. Ogni pezzo offre una sequenza di aromi che si sviluppano lentamente. Interessante e avvolgente.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(10,10,"pepate-e-selvagge","Pepate e selvagge","Le Jurassic Pepper Bites hanno il pepe giusto, non troppo, non troppo poco. Il finale intenso e profondo le rende memorabili. Ottimo snack serale!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(11,11,"fresco-come-una-brezza-giurassica","Fresco come una brezza giurassica","Il Ptero Fresh Wrap è una vera boccata d\'aria. Le verdure sono fresche e il condimento cremoso equilibra tutto perfettamente. Leggero ma profondo.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(12,12,"affumicato-e-terroso","Affumicato e terroso","Il Savanna Smoke Wrap mi ha sorpreso con la sua complessità. L\'affumicatura si intreccia perfettamente con il fondo erbaceo. Davvero intrigante.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(13,13,"ranch-preistorico","Ranch preistorico","Il Fossil Ranch Wrap è ricco e cremoso come promesso. L\'equilibrio tra affumicato, verde e dolcezza è impeccabile. Un wrap completo e soddisfacente.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(14,14,"intenso-e-memorabile","Intenso e memorabile","Il Volcanic Spicy Wrap è per chi ama il calore. La spezia arriva forte ma non copre gli altri sapori. Un\'esperienza vulcanica autenticamente riuscita.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(15,15,"equilibrato-e-raffinato","Equilibrato e raffinato","L\'Herbivore Balance Wrap dimostra che la rinuncia alla carne non significa sacrificare il sapore. Naturale, armonioso e sorprendentemente profondo.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(16,16,"patatine-incandescenti","Patatine incandescenti","Le Lava Fries hanno quella croccantezza calda e quel retrogusto fumé che le rende speciali. Un contorno che non passa inosservato. Fantastico!",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(17,17,"anelli-di-oro-paleontologico","Anelli di oro paleontologico","I Dino Onion Rings sono il perfetto equilibrio tra croccante e morbido. La nota affumicata richiama una foresta antica in modo suggestivo. Eccellenti.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(18,18,"rustico-e-mineralizzato","Rustico e mineralizzato","Le Canyon Potato Wedges hanno un carattere rustico che mi piace. Il cuore morbido e l\'esterno croccante creano un contrasto perfetto. Sostanzioso!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(19,19,"freschezza-primordiale","Freschezza primordiale","La Jurassic Coleslaw Cup è fresca e croccante. L\'acidulo bilancia bene la croccantezza vegetale. Un contorno che pulisce il palato in modo elegante.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(20,20,"dolcezza-naturale-di-un-era-lontana","Dolcezza naturale di un\'era lontana","Le Cretaceous Corn Bites hanno una dolcezza naturale affascinante. Il profilo goloso si amplifica in un finale avvolgente. Originale e piacevole.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(21,21,"ambrata-e-affumicata","Ambrata e affumicata","L\'Amber BBQ Sauce è semplicemente perfetta. Le note caramellate e affumicate non sovrrastano ma amplificano ogni piatto. Una salsa essenziale.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(22,22,"piccante-ed-audace","Piccante ed audace","La Raptor Hot Sauce è feroce in modo buono. Il calore si sviluppa lentamente e l\'affumicatura aggiunge profondità. Per chi ama l\'intensità!",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(23,23,"cremosa-e-versatile","Cremosa e versatile","La Fossil Mayo Sauce è vellutata e delicata. Perfetta per bilanciare sapori intensi. Una salsa che sembra ricordare fossili avvolti in crema.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(24,24,"affumicata-come-la-preistoria","Affumicata come la preistoria","La Smoky Tar Sauce è robusta e complessa. L\'elemento tar aggiunge profondità e arcaismo. Per chi vuole un sapore audace e ricco.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(25,25,"dolce-piccante-equilibrato","Dolce-piccante equilibrato","Il Meteor Honey Mustard è bellissimo. Il contrasto miele-mostarda è ben calibrato e il finale leggermente speziato completa perfettamente.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(26,26,"freschezza-dissetante","Freschezza dissetante","La Glacier Cola è fresca e frizzante con quella nota minerale particolare. Perfetta per accompagnare piatti intensi senza appesantire.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(27,27,"agrume-brillante","Agrume brillante","La Jurassic Lemon Soda è brillante e leggera. Un contrappunto acidulo che pulisce il palato tra i morsi. Esattamente quello che serve!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(28,28,"tropicale-e-vellutato","Tropicale e vellutato","Il Triassic Mango Shake è cremoso e ricco. Il mango maturo richiama frutti antichi e climi lussureggianti. Perfetto per una pausa dolce.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(29,29,"conforto-cremoso","Conforto cremoso","Il Bronto Vanilla Milk è avvolgente e rassicurante. La vaniglia calda ha un sapore di erbe dolci antiche. Perfetto per addolcire il pomeriggio.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(30,30,"erbaceo-e-dissetante","Erbaceo e dissetante","Il Cretaceous Iced Tea è fresco e pulito. L\'erba selvatica si sente bene e l\'acidità è delicata. Un tè freddo che sa di primordiale.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(31,31,"burroso-e-caramellato","Burroso e caramellato","Il Fossil Cookie Pie è avvolgente e fragrante. La componente croccante si intreccia perfettamente con un cuore dolce. Antichi racconti gastronomici.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(32,32,"cioccolato-profondo","Cioccolato profondo","Il Meteor Choco Sundae è ricco e intenso. Le scaglie di cioccolato e il finale leggermente tostato lo rendono memorabile. Un\'esperienza cosmica!",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(33,33,"dorato-e-caramellato","Dorato e caramellato","L\'Amber Caramel Muffin è soffice e dorato. La dolcezza è bilanciata e il retrogusto di zucchero bruciato la rende speciale. Comfort food!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(34,34,"intenso-e-umido","Intenso e umido","Il Jurassic Brownie Bite è cioccolatoso e deciso. La densità ricorda lava solidificata e il cuore umido rilascia aromi tostati. Bellissimo!",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(35,35,"cremoso-e-delicato","Cremoso e delicato","La Veloci Cream Cup è morbida e raffinata. L\'equilibrio gentile tra dolcezza e freschezza la rende perfetta. Un piccolo interludio elegante.",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(36,36,"menu-avventuroso","Menu avventuroso","Il Predator Combo Menu è vario e completo. Ogni elemento raconta una storia e i contrasti di intensità sono ben calibrati. Un\'avventura culinaria!",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(37,37,"caldo-e-accogliente","Caldo e accogliente","Il Volcano Family Menu è ricco di aromi e conviviale. La progressione di sapori è intensa ma bilanciata. Perfetto per condividere!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(38,38,"fresco-e-sorprendente","Fresco e sorprendente","L\'Explorer Lunch Menu è elegante e dinamico. Ogni piatto si rincorre con equilibrio tra note saline, erbacee e aromatiche. Un percorso intrigante!",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(39,39,"rustico-e-fume","Rustico e fumé","Il Campfire Dinner Menu evoca un falò nella notte giurassica. Gli aromi di legno bruciato e carne affumicata creano un\'atmosfera autenticamente antica.",5,0,"2026-06-10 21:11:05","2026-06-10 21:11:05"),(40,40,"solido-e-accessibile","Solido e accessibile","Il Jurassic Value Menu è ben bilanciato e autentico. Offre una sequenza gustativa coerente e soddisfacente a un prezzo accessibile. Ottima scelta!",4,0,"2026-06-10 21:11:05","2026-06-10 21:11:05");
